    @Test
    void persistence_survivesPageReload() {
        navigateToApp();
        addTodo("Persistent todo");
        addTodo("Another one");

        page.reload();

        assertThat(page.locator(".todo-list li")).hasCount(2);
        assertThat(page.locator(".todo-list li").first().locator("label")).hasText("Persistent todo");
    }
}

